It would be good if PyDrill could return a dataframe, Panel or Series directly from the query.  I'd imagine this wouldn't be all that difficult to implement.

Something like:
```
def query_dataframe(self, sql, timeout=10):
        """
        :param sql: string
        :return: pydrill.client.ResultQuery
        """
        if not sql:
            raise QueryError('No query passed to drill.')
    
    #Check first to see if pandas is available, and if not throw exception
    from pandas import DataFrame

        result = self.perform_request(**{
            'method': 'POST',
            'url': '/query.json',
            'body': {
                "queryType": "SQL",
                "query": sql
            },
            'params': {
                'request_timeout': timeout
            }
        })

        return DataFrame( result )
```

Alternatively, you could just add this as an optional arg in the ```query()``` method.  That actually might be my preference.  If you want I can code this for real and try it out.

```python

from flask import Flask, render_template
from chatterbot import ChatBot
from chatterbot.trainers import ChatterBotCorpusTrainer
import logging

logging.basicConfig(level=logging.INFO)

app = Flask(__name__)

english_bot = ChatBot("English Bot", storage_adapter="chatterbot.storage.SQLStorageAdapter",logic_adapters=[
        {
            'import_path': 'chatterbot.logic.BestMatch'
        },
        {
            'import_path': 'chatterbot.logic.LowConfidenceAdapter',
            'threshold': 0.30,
            'default_response': 'I am sorry, but I do not understand.'
        }
    ],)

english_bot.set_trainer(ChatterBotCorpusTrainer)

@app.route("/")
def home():
    return render_template("index.html")

@app.route("/get/<string:query>")
def get_raw_response(query):
    return str(english_bot.get_response(query))
@app.route("/set/<string:query>")
def set_raw_response(query):
    query_split = query.split("^^^")
    #    print query_split
    statement, response = english_bot.generate_response(english_bot.input.process_input_statement(query_split[0]), None)
    #print (statement,response)
    #statement = english_bot.input.process_input_statement(query_split[0])
    response1 = english_bot.input.process_input_statement(query_split[1])
    #print (statement,response)
    english_bot.learn_response(response1, statement)
    return str("learned ")


if __name__ == "__main__":
    app.run()
```
In this above code when i set `read only = True` then the ` english_bot.learn_response(response1, statement)` does not work as tested on flask link.But when `read only = True`  is removed the it works properly.

Something changed in 0.6.0/0.6.1 that is breaking this:
```python
from mock import MagicMock
from nose.tools import assert_true
from nose_parameterized import parameterized

class TestFoo(object):
    def setup(self):
        self.foo = MagicMock()

    def test_foo(self):
        assert_true(hasattr(self, 'foo'))  # passes

    @parameterized([
        ('bar',)
    ])
    def test_bar(self, bar_arg):
        assert_true(hasattr(self, 'foo')) # fails in 0.6.0, passes in 0.5.0
```

When an argument is declared as optional with default value in the constructor, everytime it is set by `@autoargs` the setter is called twice (once with the default value and once with the value provided by the user)

```python
global counter
counter = 0

class Home(object):
    @autoargs
    def __init__(self, foo, bar=False):
        pass

    @property
    def bar(self):
        return self._bar

    @bar.setter
    def bar(self, value):
        global counter
        counter += 1
        self._bar = value

Home(None, bar=True)
assert counter == 1  # AssertionError : counter is 2 !
```

I create both refresh token and access token when login. However, when logout, those tokens should be revoked at the same time, without affecting other tokens owned by the user.
I look at the doc. Like: 
```
# Endpoint for revoking the current users access token
@app.route('/logout', methods=['POST'])
@jwt_required
def logout():
    try:
        _revoke_current_token()
    except KeyError:
        return jsonify({
            'msg': 'Access token not found in the blacklist store'
        }), 500
    return jsonify({"msg": "Successfully logged out"}), 200


# Endpoint for revoking the current users refresh token
@app.route('/logout2', methods=['POST'])
@jwt_refresh_token_required
def logout2():
    try:
        _revoke_current_token()
    except KeyError:
        return jsonify({
            'msg': 'Refresh token not found in the blacklist store'
        }), 500
    return jsonify({"msg": "Successfully logged out"}), 200
```

Is there a way to revoke both?

